import React, { Component } from "react";
import ExpenseIcon from "./ExpenseIcon";

export default class ExpenseDetail extends Component {
  render() {
    const { expense, onSelect } = this.props;
    const { category, description, amount, date } = expense;

    let displayDescription = description || "";
    if (date && date.includes("-")) {
      const parts = date.split("-"); // YYYY-MM-DD
      const formattedDate = `${parts[1]}/${parts[2]}/${parts[0].slice(-2)}`; // MM/DD/YY
      displayDescription = `${formattedDate} - ${displayDescription}`;
    }

    return (
      <li
        className="mdc-list-item"
        onClick={() => onSelect(expense)}
      >
        <ExpenseIcon category={category} />
        <span className="mdc-list-item__text">
          {category}
          <span className="mdc-list-item__text__secondary">
            {displayDescription
              ? ` ${displayDescription.replace(/^(.{50}).+/, "$1…")}`
              : ""}
          </span>
        </span>
        <span className="mdc-list-item__end-detail">
          ${amount}
        </span>
      </li>
    );
  }
}
