import React, { Component } from "react";
import { MDCTextfield } from "@material/textfield/dist/mdc.textfield.js";
import { MDCDialog } from "@material/dialog/dist/mdc.dialog.js";

import "@material/form-field/dist/mdc.form-field.css";
import "@material/textfield/dist/mdc.textfield.css";
import "@material/button/dist/mdc.button.css";
import "@material/dialog/dist/mdc.dialog.css";

import "./expense-form/ExpenseForm.css";

class IncomeForm extends Component {
  constructor(props) {
    super(props);
    this.state = { isValid: false };
  }

  handleInputChange = (event) => {
    const target = event.target;
    const value = target.value;
    target.reportValidity();
    this.setState({ isValid: this.form.checkValidity() });
    this.props.onChange(target.name, value);
  }

  componentDidMount() {
    document.querySelectorAll(".mdc-textfield").forEach(selector => {
      new MDCTextfield(selector);
    });
    if (this.amountInput) this.amountInput.focus();
  }

  handleSubmit = (event) => {
    event.preventDefault();
    this.props.onSubmit();
  }

  initializeDeleteModal = (element) => {
    if (element) {
      this.dialog = new MDCDialog(element);
      this.dialog.listen("MDCDialog:accept", () => {
        document.body.className = document.body.className.replace("mdc-dialog-scroll-lock", "");
        this.props.onDelete(this.props.income);
      });
    }
  }

  render() {
    const { income } = this.props;
    return (
      <form onSubmit={this.handleSubmit} ref={form => { this.form = form; }} noValidate>
        <aside className="mdc-dialog" ref={this.initializeDeleteModal}>
          <div className="mdc-dialog__surface">
            <header className="mdc-dialog__header">
              <h2 className="mdc-dialog__header__title">Are you sure?</h2>
            </header>
            <section className="mdc-dialog__body">Do you really want to delete this income record?</section>
            <footer className="mdc-dialog__footer">
              <button type="button" className="mdc-button mdc-dialog__footer__button mdc-dialog__footer__button--cancel">Cancel</button>
              <button type="button" className="mdc-button mdc-dialog__footer__button mdc-dialog__footer__button--accept">Delete</button>
            </footer>
          </div>
        </aside>

        <div className="mdc-form-field">
          <div className="mdc-textfield">
            <input
              name="quote"
              className="mdc-textfield__input"
              ref={el => { this.amountInput = el; }}
              value={income.quote}
              onChange={this.handleInputChange}
              type="number"
              step="0.01"
              min="0"
              required
            />
            <label className="mdc-textfield__label">Quote</label>
          </div>
        </div>

        <div className="mdc-form-field">
          <div className="mdc-textfield">
            <input
              name="amount"
              className="mdc-textfield__input"
              value={income.amount}
              onChange={this.handleInputChange}
              type="number"
              step="0.01"
              min="0"
            />
            <label className="mdc-textfield__label">Actual Received</label>
          </div>
        </div>

        <div className="mdc-form-field">
          <div className="mdc-textfield">
            <input
              name="client"
              className="mdc-textfield__input"
              value={income.client}
              onChange={this.handleInputChange}
              type="text"
              required
            />
            <label className="mdc-textfield__label">Client</label>
          </div>
        </div>

        <div className="mdc-form-field">
          <div className="mdc-textfield">
            <input
              name="description"
              className="mdc-textfield__input"
              value={income.description}
              onChange={this.handleInputChange}
              type="text"
            />
            <label className="mdc-textfield__label">Description</label>
          </div>
        </div>

        <div className="mdc-form-field">
          <div className="mdc-textfield">
            <input
              name="date"
              className="mdc-textfield__input"
              value={income.date}
              onChange={this.handleInputChange}
              type="date"
              required
            />
            <label className="mdc-textfield__label"></label>
          </div>
        </div>

        <div className="mdc-form-field mdc-form-submit">
          <input
            type="submit"
            className="mdc-button"
            value={income.id ? "Update" : "Add"}
            disabled={!this.state.isValid}
          />
          {income.id && (
            <input
              type="button"
              className="mdc-button"
              onClick={() => this.dialog.show()}
              value="Delete"
            />
          )}
          <input
            type="button"
            className="mdc-button"
            onClick={() => this.props.onCancel()}
            value="Close"
          />
        </div>
      </form>
    );
  }
}

export default IncomeForm;
